/* SPDX-License-Identifier: AGPL-3.0-or-later
 * Copyright 2026 Cave Runtime contributors
 *
 * htmx.min.js — minimal htmx-compatible shim covering exactly the
 * attribute surface cave-portal uses today:
 *   - hx-get="<url>"
 *   - hx-post="<url>"
 *   - hx-target="<css selector>"
 *   - hx-swap="innerHTML"        (the only swap mode we emit)
 *   - hx-encoding="multipart/form-data"  (forms with file uploads)
 *
 * Anything beyond that (hx-trigger / oob swaps / SSE / WebSockets /
 * out-of-band / boost / etc.) is intentionally NOT implemented — those
 * features are not used anywhere in src/admin/ as of 2026-05-22, and
 * shipping the full ~50 KB htmx upstream just to support unused
 * features bloats every admin page. If a future commit adds a real
 * htmx feature, swap this shim for the upstream htmx 2.x build.
 *
 * The shim deliberately ignores the response Content-Type — handlers
 * already return HTML fragments for hx-* endpoints.
 */
(function () {
  "use strict";

  function attr(el, name) { return el.getAttribute ? el.getAttribute(name) : null; }

  function targetEl(trigger) {
    var sel = attr(trigger, "hx-target");
    if (!sel) return trigger;
    if (sel === "this") return trigger;
    try { return document.querySelector(sel) || trigger; } catch (_) { return trigger; }
  }

  function swapHtml(target, html) {
    // We only support hx-swap="innerHTML" (the codebase default).
    target.innerHTML = html;
    // Re-process new descendants so nested hx-* attributes wire up.
    processSubtree(target);
  }

  function showErr(target, msg) {
    var div = document.createElement("div");
    div.className = "cave-error";
    div.textContent = "Request failed: " + msg;
    target.innerHTML = "";
    target.appendChild(div);
  }

  function doFetch(method, url, target, body, opts) {
    var init = { method: method, credentials: "same-origin", headers: { "HX-Request": "true" } };
    if (body) init.body = body;
    fetch(url, init)
      .then(function (r) {
        if (!r.ok) throw new Error(r.status + " " + r.statusText);
        return r.text();
      })
      .then(function (html) { swapHtml(target, html); })
      .catch(function (e) { showErr(target, e.message || String(e)); });
  }

  function onClickGet(ev) {
    var el = ev.currentTarget;
    var url = attr(el, "hx-get");
    if (!url) return;
    ev.preventDefault();
    doFetch("GET", url, targetEl(el));
  }

  function onClickPost(ev) {
    var el = ev.currentTarget;
    var url = attr(el, "hx-post");
    if (!url) return;
    ev.preventDefault();
    doFetch("POST", url, targetEl(el));
  }

  function onSubmit(ev) {
    var form = ev.currentTarget;
    var url = attr(form, "hx-post") || attr(form, "hx-get") || form.action;
    if (!url) return;
    var method = attr(form, "hx-post") ? "POST" : (attr(form, "hx-get") ? "GET" : (form.method || "GET").toUpperCase());
    ev.preventDefault();
    var enc = attr(form, "hx-encoding") || form.enctype || "application/x-www-form-urlencoded";
    var body = null;
    if (method !== "GET") {
      body = enc === "multipart/form-data" ? new FormData(form) : new URLSearchParams(new FormData(form));
    }
    doFetch(method, url, targetEl(form), body);
  }

  var WIRED = "__caveHxWired";

  function processSubtree(root) {
    if (!root.querySelectorAll) return;
    root.querySelectorAll("[hx-get]").forEach(function (el) {
      if (el[WIRED + "G"]) return;
      el[WIRED + "G"] = true;
      el.addEventListener("click", onClickGet);
    });
    root.querySelectorAll("[hx-post]").forEach(function (el) {
      if (el.tagName === "FORM") return;
      if (el[WIRED + "P"]) return;
      el[WIRED + "P"] = true;
      el.addEventListener("click", onClickPost);
    });
    root.querySelectorAll("form[hx-post], form[hx-get]").forEach(function (form) {
      if (form[WIRED + "F"]) return;
      form[WIRED + "F"] = true;
      form.addEventListener("submit", onSubmit);
    });
  }

  function init() { processSubtree(document.body); }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }

  // Expose a tiny surface so callers can re-process injected fragments.
  window.htmx = { process: processSubtree, version: "cave-shim-1.0" };
})();
